1	"use client";
2	
3	import { useTickets } from "@/shared/api/query-hooks/use-tickets";
4	import { APP_ROUTES } from "@/shared/config/app-routes";
5	import { QuestionsEnquiriesSection } from "@/shared/ui/questions-enquiries-section";
6	import {
7	  ACTIVE_TICKET_STATUSES,
8	  ARCHIVE_TICKET_STATUSES,
9	  TICKET_CATEGORY_LABELS,
10	  TICKET_STATUS_LABELS,
11	} from "@/shared/constants/ticket";
12	import {
13	  Select,
14	  SelectContent,
15	  SelectItem,
16	  SelectTrigger,
17	  SelectValue,
18	} from "@/shared/ui/select";
19	import type { TicketListItem } from "@/shared/types/ticket.types";
20	import { TicketStatus } from "@/shared/types/ticket.types";
21	import { useSession } from "next-auth/react";
22	import Link from "next/link";
23	import { useRouter } from "next/navigation";
24	import { type ReactNode, Suspense, useState } from "react";
25	
26	
27	const STATUS_TEXT_COLORS: Record<TicketStatus, string> = {
28	  [TicketStatus.Open]: "text-[#059669]",
29	  [TicketStatus.Resolved]: "text-[#059669]",
30	  [TicketStatus.Rejected]: "text-[#DC2626]",
31	  [TicketStatus.Cancelled]: "text-[#6B7280]",
32	};
33	
34	type FilterValue = "all" | "active" | "archive";
35	
36	function SupportPageContent() {
37	  const { status } = useSession();
38	  const isAuthenticated = status === "authenticated";
39	  const isSessionLoading = status === "loading";
40	
41	  const router = useRouter();
42	  const [filter, setFilter] = useState<FilterValue>("all");
43	
44	  function getStatuses() {
45	    if (filter === "active") return ACTIVE_TICKET_STATUSES;
46	    if (filter === "archive") return ARCHIVE_TICKET_STATUSES;
47	    return;
48	  }
49	  const statuses = getStatuses();
50	
51	  const { data, isLoading } = useTickets({ statuses }, isAuthenticated);
52	
53	  const tickets = data?.data ?? [];
54	  const ticketCount = data?.total ?? 0;
55	
56	  return (
57	    <div className="mb-10 flex flex-col">
58	      {/* Page header */}
59	      <div className="mb-8 flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
60	        <h1 className="font-extralight font-new-serif text-4xl text-[#44403C] leading-[120%]">
61	          Support
62	        </h1>
63	        <Link
64	          href={APP_ROUTES.TICKETS.CREATE}
65	          className="inline-flex h-10 w-fit items-center gap-2 rounded border border-[#44403C] bg-transparent px-4 font-new-sans text-[#44403C] text-sm transition-colors hover:bg-[#EDE9E3]"
66	        >
67	          Raise Ticket
68	          <svg
69	            width="14"
70	            height="14"
71	            viewBox="0 0 14 14"
72	            fill="none"
73	            aria-hidden="true"
74	          >
75	            <path
76	              d="M7 1v12M1 7h12"
77	              stroke="currentColor"
78	              strokeWidth="1.5"
79	              strokeLinecap="round"
80	            />
81	          </svg>
82	        </Link>
83	      </div>
84	
85	      {/* Count + filter */}
86	      <div className="mb-4 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
87	        <div className="flex flex-col gap-0.5">
88	          <p className="font-medium font-new-sans text-[#44403C]">
89	            {isAuthenticated ? ticketCount : 0} Support Requests
90	          </p>
91	          <p className="font-new-sans text-[#A8A29E] text-sm">
92	            This is a record of all your Support Requests
93	          </p>
94	        </div>
95	        <Select
96	          value={filter}
97	          onValueChange={(val) => setFilter(val as FilterValue)}
98	          disabled={!isAuthenticated}
99	        >
100	          <SelectTrigger className="h-10 w-full rounded border border-[#D6D3D1] bg-[#F5F3EF] font-new-sans text-[#44403C] text-sm sm:w-[180px]">
101	            <SelectValue />
102	          </SelectTrigger>
103	          <SelectContent>
104	            <SelectItem value="all">All Tickets</SelectItem>
105	            <SelectItem value="active">Active</SelectItem>
106	            <SelectItem value="archive">Archive</SelectItem>
107	          </SelectContent>
108	        </Select>
109	      </div>
110	
111	      {/* Ticket list area */}
112	      <div className="mb-16 min-h-[320px] overflow-hidden rounded-xl border border-[#D6D3D1] bg-[#F5F3EF]">
113	        <TicketListContent
114	          isLoading={isSessionLoading || (isAuthenticated && isLoading)}
115	          isAuthenticated={isAuthenticated}
116	          tickets={tickets}
117	          onTicketClick={(id) => router.push(`/support/${id}`)}
118	        />
119	      </div>
120	
121	      {/* Questions or enquiries — full bleed */}
122	      <div className="-mb-4 min-[1172px]:-mb-8 mr-[calc(-50vw+50%)] ml-[calc(-50vw+50%)]">
123	        <QuestionsEnquiriesSection />
124	      </div>
125	    </div>
126	  );
127	}
128	
129	function TicketTableRow({
130	  ticket,
131	  onClick,
132	}: {
133	  ticket: TicketListItem;
134	  onClick: () => void;
135	}) {
136	  const ticketId = `Ticket${ticket.id.replace(/-/g, "").slice(0, 5).toUpperCase()}`;
137	  const date = new Date(ticket.createdAt).toLocaleDateString("en-AE", {
138	    day: "numeric",
139	    month: "short",
140	    year: "numeric",
141	  });
142	
143	  return (
144	    <tr
145	      className="cursor-pointer border-[#E7E5E4] border-t transition-colors hover:bg-[#EDE9E3]"
146	      onClick={onClick}
147	    >
148	      <td className="py-4 pr-3 pl-6 font-new-sans text-[#44403C] text-sm">
149	        {ticketId}
150	      </td>
151	      <td className="px-3 py-4 font-new-sans text-[#44403C] text-sm">{date}</td>
152	      <td className="px-3 py-4 font-new-sans text-[#44403C] text-sm">
153	        {TICKET_CATEGORY_LABELS[ticket.category]}
154	      </td>
155	      <td className="px-3 py-4 font-new-sans text-[#44403C] text-sm">
156	        {ticket.referenceId ?? "N/A"}
157	      </td>
158	      <td className="max-w-[320px] px-3 py-4">
159	        <span className="flex items-center gap-1.5 font-new-sans text-[#44403C] text-sm">
160	          <PaperclipIcon />
161	          <span className="truncate">{ticket.subject}</span>
162	        </span>
163	      </td>
164	      <td className="px-3 py-4">
165	        <span
166	          className={`font-medium font-new-sans text-sm ${STATUS_TEXT_COLORS[ticket.status]}`}
167	        >
168	          {TICKET_STATUS_LABELS[ticket.status]}
169	        </span>
170	      </td>
171	      <td className="py-4 pr-4 pl-3">
172	        <button
173	          type="button"
174	          onClick={onClick}
175	          className="flex size-8 items-center justify-center rounded-full border border-[#D6D3D1] transition-colors hover:border-[#44403C]"
176	          aria-label="View ticket"
177	        >
178	          <svg
179	            width="14"
180	            height="14"
181	            viewBox="0 0 14 14"
182	            fill="none"
183	            aria-hidden="true"
184	          >
185	            <path
186	              d="M3 7h8M7.5 3.5L11 7l-3.5 3.5"
187	              stroke="#44403C"
188	              strokeWidth="1.5"
189	              strokeLinecap="round"
190	              strokeLinejoin="round"
191	            />
192	          </svg>
193	        </button>
194	      </td>
195	    </tr>
196	  );
197	}
198	
199	function PaperclipIcon() {
200	  return (
201	    <svg
202	      width="13"
203	      height="13"
204	      viewBox="0 0 24 24"
205	      fill="none"
206	      aria-hidden="true"
207	      className="shrink-0 text-[#A8A29E]"
208	    >
209	      <path
210	        d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48"
211	        stroke="currentColor"
212	        strokeWidth="1.5"
213	        strokeLinecap="round"
214	        strokeLinejoin="round"
215	      />
216	    </svg>
217	  );
218	}
219	
220	type SortKey = "date" | "category" | "related" | "subject" | "status";
221	type SortDir = "asc" | "desc";
222	
223	interface ColumnDef {
224	  label: string;
225	  sortKey?: SortKey;
226	}
227	
228	const COLUMNS: ColumnDef[] = [
229	  { label: "Ticket ID" },
230	  { label: "Date", sortKey: "date" },
231	  { label: "Issue Category", sortKey: "category" },
232	  { label: "Related", sortKey: "related" },
233	  { label: "Description", sortKey: "subject" },
234	  { label: "Status", sortKey: "status" },
235	  { label: "Actions" },
236	];
237	
238	function sortTickets(
239	  tickets: TicketListItem[],
240	  key: SortKey,
241	  dir: SortDir,
242	): TicketListItem[] {
243	  return [...tickets].sort((aa, bb) => {
244	    let cmp = 0;
245	    if (key === "date") {
246	      cmp = new Date(aa.createdAt).getTime() - new Date(bb.createdAt).getTime();
247	    } else if (key === "category") {
248	      cmp = aa.category.localeCompare(bb.category);
249	    } else if (key === "related") {
250	      cmp = (aa.referenceId ?? "").localeCompare(bb.referenceId ?? "");
251	    } else if (key === "subject") {
252	      cmp = aa.subject.localeCompare(bb.subject);
253	    } else if (key === "status") {
254	      cmp = aa.status.localeCompare(bb.status);
255	    }
256	    return dir === "asc" ? cmp : -cmp;
257	  });
258	}
259	
260	function SortIcon({ active, dir }: { active: boolean; dir: SortDir }) {
261	  return (
262	    <svg
263	      width="12"
264	      height="12"
265	      viewBox="0 0 12 12"
266	      fill="none"
267	      aria-hidden="true"
268	      className="shrink-0"
269	    >
270	      <path
271	        d="M6 1v10M3 4l3-3 3 3"
272	        stroke={active && dir === "asc" ? "#44403C" : "#D6D3D1"}
273	        strokeWidth="1.2"
274	        strokeLinecap="round"
275	        strokeLinejoin="round"
276	      />
277	      <path
278	        d="M3 8l3 3 3-3"
279	        stroke={active && dir === "desc" ? "#44403C" : "#D6D3D1"}
280	        strokeWidth="1.2"
281	        strokeLinecap="round"
282	        strokeLinejoin="round"
283	      />
284	    </svg>
285	  );
286	}
287	
288	function TicketListContent({
289	  isLoading,
290	  isAuthenticated,
291	  tickets,
292	  onTicketClick,
293	}: {
294	  isLoading: boolean;
295	  isAuthenticated: boolean;
296	  tickets: TicketListItem[];
297	  onTicketClick: (id: string) => void;
298	}) {
299	  const [sortKey, setSortKey] = useState<SortKey>("date");
300	  const [sortDir, setSortDir] = useState<SortDir>("desc");
301	
302	  function handleSort(key: SortKey) {
303	    if (sortKey === key) {
304	      setSortDir((prev) => (prev === "asc" ? "desc" : "asc"));
305	    } else {
306	      setSortKey(key);
307	      setSortDir("asc");
308	    }
309	  }
310	
311	  if (isLoading) return <TicketSkeleton />;
312	  if (!isAuthenticated) return <GuestEmptyState />;
313	  if (tickets.length === 0) return <AuthEmptyState />;
314	
315	  const sorted = sortTickets(tickets, sortKey, sortDir);
316	
317	  return (
318	    <div className="w-full overflow-x-auto">
319	      <table className="w-full min-w-[700px]">
320	        <thead>
321	          <tr className="border-[#E7E5E4] border-b">
322	            {COLUMNS.map((col) => (
323	              <th
324	                key={col.label}
325	                className="py-3 pr-3 pl-6 text-left first:pl-6 last:pr-4"
326	              >
327	                {col.sortKey ? (
328	                  <button
329	                    type="button"
330	                    onClick={() => handleSort(col.sortKey as SortKey)}
331	                    className="flex items-center gap-1 font-medium font-new-sans text-[#A8A29E] text-xs transition-colors hover:text-[#44403C]"
332	                  >
333	                    {col.label}
334	                    <SortIcon active={sortKey === col.sortKey} dir={sortDir} />
335	                  </button>
336	                ) : (
337	                  <span className="font-medium font-new-sans text-[#A8A29E] text-xs">
338	                    {col.label}
339	                  </span>
340	                )}
341	              </th>
342	            ))}
343	          </tr>
344	        </thead>
345	        <tbody>
346	          {sorted.map((ticket) => (
347	            <TicketTableRow
348	              key={ticket.id}
349	              ticket={ticket}
350	              onClick={() => onTicketClick(ticket.id)}
351	            />
352	          ))}
353	        </tbody>
354	      </table>
355	    </div>
356	  );
357	}
358	
359	function TicketSkeleton() {
360	  return (
361	    <div className="flex flex-col gap-3 p-6">
362	      {[1, 2, 3].map((i) => (
363	        <div key={i} className="h-16 animate-pulse rounded-xl bg-[#EDE9E3]" />
364	      ))}
365	    </div>
366	  );
367	}
368	
369	function EmptyStateWrapper({ children }: { children: ReactNode }) {
370	  return (
371	    <div className="flex flex-col items-center gap-3 px-6 py-16 text-center">
372	      <svg
373	        width="28"
374	        height="28"
375	        viewBox="0 0 24 24"
376	        fill="none"
377	        aria-hidden="true"
378	      >
379	        <path
380	          d="M10 13a5 5 0 007.54.54l3-3a5 5 0 00-7.07-7.07l-1.72 1.71"
381	          stroke="#A8A29E"
382	          strokeWidth="1.5"
383	          strokeLinecap="round"
384	          strokeLinejoin="round"
385	        />
386	        <path
387	          d="M14 11a5 5 0 00-7.54-.54l-3 3a5 5 0 007.07 7.07l1.71-1.71"
388	          stroke="#A8A29E"
389	          strokeWidth="1.5"
390	          strokeLinecap="round"
391	          strokeLinejoin="round"
392	        />
393	      </svg>
394	      {children}
395	    </div>
396	  );
397	}
398	
399	function GuestEmptyState() {
400	  return (
401	    <EmptyStateWrapper>
402	      <div className="flex flex-col gap-1">
403	        <p className="font-medium font-new-sans text-[#A8A29E]">
404	          Nothing to see here yet
405	        </p>
406	        <p className="font-new-sans text-[#A8A29E] text-sm">
407	          Login to see your created support tickets
408	        </p>
409	      </div>
410	    </EmptyStateWrapper>
411	  );
412	}
413	
414	function AuthEmptyState() {
415	  return (
416	    <EmptyStateWrapper>
417	      <div className="flex flex-col gap-1">
418	        <p className="font-medium font-new-sans text-[#A8A29E]">
419	          Nothing to see here yet
420	        </p>
421	        <p className="font-new-sans text-[#A8A29E] text-sm">
422	          You haven't created any support tickets.
423	        </p>
424	      </div>
425	      <Link
426	        href={APP_ROUTES.TICKETS.CREATE}
427	        className="mt-2 inline-flex h-10 items-center justify-center rounded-lg border border-[#A8A29E] bg-[#F5F3EF] px-5 font-new-sans text-[#44403C] text-sm transition-colors hover:bg-[#EDE9E3]"
428	      >
429	        Raise your first ticket
430	      </Link>
431	    </EmptyStateWrapper>
432	  );
433	}
434	
435	
436	export default function SupportPage() {
437	  return (
438	    <Suspense
439	      fallback={
440	        <div className="flex flex-col gap-3 pt-4">
441	          {[1, 2, 3].map((i) => (
442	            <div
443	              key={i}
444	              className="h-16 animate-pulse rounded-xl bg-[#EDE9E3]"
445	            />
446	          ))}
447	        </div>
448	      }
449	    >
450	      <SupportPageContent />
451	    </Suspense>
452	  );
453	}
