1	"use client";
2	
3	import { APP_ROUTES } from "@/shared/config/app-routes";
4	import { SidebarProvider } from "@/shared/contexts/sidebar-context";
5	import { AuthenticatedHeader } from "@/widgets/authenticated-header";
6	import { Footer } from "@/widgets/footer";
7	import { Header } from "@/widgets/header";
8	import { usePathname } from "next/navigation";
9	import type { FC, ReactNode } from "react";
10	import { useState } from "react";
11	
12	interface AuthenticatedLayoutProps {
13	  children: ReactNode;
14	}
15	
16	const NEW_DESIGN_ROUTES = [
17	  "/wallet",
18	  APP_ROUTES.PROFILE,
19	  "/my-offers",
20	  "/quote-request/create",
21	  "/quote-request",
22	  "/buybacks",
23	  "/tickets",
24	  "/support",
25	  "/welcome",
26	];
27	
28	const NO_FOOTER_ROUTES = ["/welcome"];
29	
30	export const AuthenticatedLayout: FC<AuthenticatedLayoutProps> = ({
31	  children,
32	}) => {
33	  const pathname = usePathname();
34	  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
35	
36	  const isNewDesign =
37	    NEW_DESIGN_ROUTES.some(
38	      (route) => pathname === route || pathname.startsWith(`${route}/`)
39	    ) ||
40	    (pathname.startsWith("/buybacks/") && pathname.endsWith("/pay"));
41	
42	  const showFooter = !NO_FOOTER_ROUTES.some(
43	    (route) => pathname === route || pathname.startsWith(`${route}/`)
44	  );
45	
46	  if (isNewDesign) {
47	    return (
48	      <div className="flex min-h-screen flex-col">
49	        <div
50	          className="new-design -z-50 fixed top-0 left-0 min-h-screen w-full bg-background"
51	          id="background"
52	        />
53	        <Header />
54	        <main className="flex-1">
55	          <div className="mx-auto my-[62px] max-w-[1720px] px-4 min-[1172px]:px-10 min-[1172px]:py-8">
56	            {children}
57	          </div>
58	        </main>
59	        {showFooter && <Footer />}
60	      </div>
61	    );
62	  }
63	
64	  return (
65	    <SidebarProvider
66	      value={{
67	        onMenuClick: () => setIsSidebarOpen(true),
68	        isOpen: isSidebarOpen,
69	        setIsOpen: setIsSidebarOpen,
70	      }}
71	    >
72	      <div className="flex min-h-screen flex-col">
73	        {isNewDesign ? <Header /> : <AuthenticatedHeader />}
74	        <main className="my-20 flex-1">{children}</main>
75	        {isNewDesign && <Footer />}
76	      </div>
77	    </SidebarProvider>
78	  );
79	};
