1	"use client";
2	
3	import { useCancelTicket, useDeleteTicket, useTicket } from "@/shared/api/query-hooks/use-tickets";
4	import { ApiKeys } from "@/shared/api/query-keys";
5	import { useQueryClient } from "@tanstack/react-query";
6	import {
7	  TICKET_CATEGORY_LABELS,
8	  TICKET_STATUS_LABELS,
9	} from "@/shared/constants/ticket";
10	import { TicketStatus } from "@/shared/types/ticket.types";
11	import { toast } from "@/shared/ui/notification";
12	import { format } from "date-fns";
13	import Link from "next/link";
14	import { useParams, useRouter } from "next/navigation";
15	import { Suspense } from "react";
16	
17	const STATUS_BADGE: Record<TicketStatus, string> = {
18	  [TicketStatus.Open]: "bg-[#D1FAE5] text-[#065F46]",
19	  [TicketStatus.Resolved]: "bg-[#D1FAE5] text-[#065F46]",
20	  [TicketStatus.Rejected]: "bg-[#FEE2E2] text-[#B91C1C]",
21	  [TicketStatus.Cancelled]: "bg-[#F3F4F6] text-[#6B7280]",
22	};
23	
24	function SupportTicketDetail({ ticketId }: { ticketId: string }) {
25	  const router = useRouter();
26	  const queryClient = useQueryClient();
27	  const { data: ticket, isLoading } = useTicket(ticketId);
28	  const deleteMutation = useDeleteTicket();
29	  const cancelMutation = useCancelTicket();
30	
31	  function navigateToSupport() {
32	    queryClient.removeQueries({ queryKey: ApiKeys.tickets() });
33	    router.push("/support");
34	  }
35	
36	  function handleDelete() {
37	    deleteMutation.mutate(ticketId, {
38	      onSuccess: () => {
39	        toast.success("Ticket deleted successfully");
40	        navigateToSupport();
41	      },
42	      onError: () => {
43	        toast.error("Failed to delete ticket");
44	      },
45	    });
46	  }
47	
48	  function handleArchive() {
49	    if (ticket?.status !== TicketStatus.Open) {
50	      navigateToSupport();
51	      return;
